import{_ as l,C as i,o as A,c as d,a5 as e,b as s,w as o,a as r,E,a4 as n}from"./chunks/framework.gGRxziV4.js";const f=JSON.parse('{"title":"01-项目全景：ECC 不只是一堆配置文件，它是 AI Agent 的\\"缰绳\\"","description":"","frontmatter":{},"headers":[],"relativePath":"08-ECC教程/01-项目全景.md","filePath":"08-ECC教程/01-项目全景.md","lastUpdated":null}'),u={name:"08-ECC教程/01-项目全景.md"};function C(p,t,B,h,g,q){const a=i("Mermaid");return A(),d("div",null,[t[2]||(t[2]=e('<h1 id="_01-项目全景-ecc-不只是一堆配置文件-它是-ai-agent-的-缰绳" tabindex="-1">01-项目全景：ECC 不只是一堆配置文件，它是 AI Agent 的&quot;缰绳&quot; <a class="header-anchor" href="#_01-项目全景-ecc-不只是一堆配置文件-它是-ai-agent-的-缰绳" aria-label="Permalink to &quot;01-项目全景：ECC 不只是一堆配置文件，它是 AI Agent 的&quot;缰绳&quot;&quot;">​</a></h1><hr><h2 id="先讲个概念-什么是-agent-harness" tabindex="-1">先讲个概念：什么是 Agent Harness？ <a class="header-anchor" href="#先讲个概念-什么是-agent-harness" aria-label="Permalink to &quot;先讲个概念：什么是 Agent Harness？&quot;">​</a></h2><p>&quot;Harness&quot;这个词你可能在编程里见过——测试框架叫 Test Harness，CI/CD 工具叫 Build Harness。但它的原意其实是<strong>马具</strong>——就是马鞍、缰绳这些东西。</p><p>一匹马很强壮，能日行千里。但如果你直接骑上去，没有马鞍你坐不稳，没有缰绳你控制不了方向。马再好，你驾驭不了也没用。</p><p><strong>AI Agent 也是一样的。</strong> Claude Code 是那匹强壮的马——TA 能写代码、能理解需求、能做复杂的工程任务。但如果你不给 TA 装上&quot;缰绳&quot;，你就会发现：</p><ul><li>TA 不知道你的项目规矩是什么</li><li>TA 做完事不知道主动汇报</li><li>TA 经常忘记之前的上下文</li><li>TA 可能做出危险操作（比如把密钥提交到 GitHub）</li></ul><p><strong>ECC 就是那套 Harness。</strong> 它不是马本身（Claude Code），也不是骑手（你），而是让骑手能安全、高效地控制马的那套系统。</p><p>这个比喻很关键，因为很多人把 ECC 理解成&quot;一堆配置文件&quot;。不是的。配置文件只是 Harness 的零件，ECC 是把这些零件组装起来形成一套完整的控制系统。</p><hr><h2 id="为什么是这六个模块-一个完整的控制系统" tabindex="-1">为什么是这六个模块？一个完整的控制系统 <a class="header-anchor" href="#为什么是这六个模块-一个完整的控制系统" aria-label="Permalink to &quot;为什么是这六个模块？一个完整的控制系统&quot;">​</a></h2><p>如果你去研究 ECC 的目录结构，你会发现六个主要模块。看起来像是随意堆砌的？其实不是。这六个模块构成了一个完整的&quot;控制系统&quot;，每个模块负责控制链的一个环节：</p>',12)),(A(),s(n,null,{default:o(()=>[E(a,{id:"mermaid-51",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20CTRL%5B%22ECC%20%E6%8E%A7%E5%88%B6%E7%B3%BB%E7%BB%9F%22%5D%0A%20%20%20%20%20%20%20%20direction%20TB%0A%20%20%20%20%20%20%20%20HOOKS%5B%22%F0%9F%AA%9D%20Hooks%5Cn%E6%84%9F%E7%9F%A5%E5%B1%82%5Cn%E7%9F%A5%E9%81%93%E4%BB%80%E4%B9%88%E6%97%B6%E5%80%99%E8%AF%A5%E5%81%9A%E4%BB%80%E4%B9%88%22%5D%0A%20%20%20%20%20%20%20%20AGENTS%5B%22%F0%9F%91%A5%20Agents%5Cn%E6%89%A7%E8%A1%8C%E5%B1%82%5Cn%E8%AE%A9%E5%AF%B9%E7%9A%84%E4%BA%BA%E5%B9%B2%E5%AF%B9%E7%9A%84%E4%BA%8B%22%5D%0A%20%20%20%20%20%20%20%20COMMANDS%5B%22%E2%9A%A1%20Commands%5Cn%E6%8E%A5%E5%8F%A3%E5%B1%82%5Cn%E4%B8%80%E4%B8%AA%E6%96%9C%E6%9D%A0%E8%A7%A6%E5%8F%91%E5%A4%8D%E6%9D%82%E6%93%8D%E4%BD%9C%22%5D%0A%20%20%20%20%20%20%20%20SKILLS%5B%22%F0%9F%93%9A%20Skills%5Cn%E7%BB%8F%E9%AA%8C%E5%B1%82%5Cn%E9%81%87%E5%88%B0%E9%97%AE%E9%A2%98%E7%9F%A5%E9%81%93%E6%80%8E%E4%B9%88%E5%A4%84%E7%90%86%22%5D%0A%20%20%20%20%20%20%20%20RULES%5B%22%F0%9F%93%8B%20Rules%5Cn%E7%BA%AA%E5%BE%8B%E5%B1%82%5Cn%E8%A7%84%E7%9F%A9%E5%86%99%E6%AD%BB%EF%BC%8C%E4%B8%8D%E7%94%A8%E9%87%8D%E5%A4%8D%E8%AF%B4%22%5D%0A%20%20%20%20%20%20%20%20SCRIPTS%5B%22%F0%9F%94%A7%20Scripts%5Cn%E5%9F%BA%E5%BB%BA%E5%B1%82%5Cn%E5%AE%89%E8%A3%85%E3%80%81%E8%BF%81%E7%A7%BB%E3%80%81%E6%A3%80%E6%9F%A5%E6%A0%B7%E6%A0%B7%E9%80%9A%22%5D%0A%0A%20%20%20%20%20%20%20%20HOOKS%20--%3E%20AGENTS%0A%20%20%20%20%20%20%20%20COMMANDS%20--%3E%20AGENTS%0A%20%20%20%20%20%20%20%20SKILLS%20--%3E%20AGENTS%0A%20%20%20%20%20%20%20%20RULES%20--%3E%20AGENTS%0A%20%20%20%20%20%20%20%20SCRIPTS%20-.-%3E%7C%22%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%E6%94%AF%E6%92%91%22%7C%20HOOKS%0A%20%20%20%20%20%20%20%20SCRIPTS%20-.-%3E%7C%22%E5%9F%BA%E7%A1%80%E8%AE%BE%E6%96%BD%E6%94%AF%E6%92%91%22%7C%20COMMANDS%0A%20%20%20%20end%0A%0A%20%20%20%20style%20HOOKS%20fill%3A%23e91e63%2Ccolor%3A%23fff%0A%20%20%20%20style%20AGENTS%20fill%3A%239c27b0%2Ccolor%3A%23fff%0A%20%20%20%20style%20COMMANDS%20fill%3A%2300bcd4%2Ccolor%3A%23fff%0A%20%20%20%20style%20SKILLS%20fill%3A%234caf50%2Ccolor%3A%23fff%0A%20%20%20%20style%20RULES%20fill%3A%23673ab7%2Ccolor%3A%23fff%0A%20%20%20%20style%20SCRIPTS%20fill%3A%233f51b5%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[r(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=e('<p>让我用人话解释每个模块为什么存在：</p><p><strong>🪝 Hooks（感知层）—— &quot;什么时候该做什么&quot;</strong></p><p>没有 Hooks，Claude Code 是一个&quot;没有触觉的机器人&quot;。TA 不知道自己刚改了一个文件，不知道应该去格式化一下，不知道工作结束了应该存个档。Hooks 就是给 TA 装上&quot;触觉&quot;：在正确的时刻触发正确的动作。</p><p><strong>👥 Agents（执行层）—— &quot;让对的人干对的事&quot;</strong></p><p>一个 AI 什么都干，等于什么都不精。就像一个公司里，你不能让一个人又做前端、又做后端、又做测试、又做安全审计。Agent 系统把这些工作分配给专门的&quot;专家&quot;——每个专家的 system prompt 更短更精准，做的事更聚焦。</p><p><strong>⚡ Commands（接口层）—— &quot;一个斜杠搞定&quot;</strong></p><p>你经常要做的一套操作，比如&quot;规划 → 设计 → 写代码 → 审查&quot;。如果每次都要用自然语言描述一遍，太麻烦了。Commands 把这些流程封装成一个 <code>/plan</code> 或 <code>/tdd</code>——就像 VS Code 的快捷键，按一下就执行一套复杂操作。</p><p><strong>📚 Skills（经验层）—— &quot;遇到问题翻菜谱&quot;</strong></p><p>有些知识是领域特定的：TypeScript 怎么排查类型错误、Rust 怎么处理生命周期、React 性能怎么优化。这些知识不需要每次都从头教 AI——以 Skill 的形式存储，AI 遇到对应问题时自动查阅就行。就像厨师做菜前翻菜谱，而不是凭记忆从头想。</p><p><strong>📋 Rules（纪律层）—— &quot;规矩立好，不用重复说&quot;</strong></p><p>&quot;代码要用 TypeScript strict 模式&quot;、&quot;变量命名用 camelCase&quot;、&quot;提交前必须跑测试&quot;。这些规矩你跟 AI 说了十遍，第十一次 TA 还是会忘。Rules 把规矩写死在配置文件里，每次工作时自动加载。AI 不用&quot;记住&quot;规矩，规矩会自动&quot;告诉&quot;TA。</p><p><strong>🔧 Scripts（基建层）—— &quot;让一切能跑起来&quot;</strong></p><p>安装、迁移、健康检查、环境检测。这些是基础设施，不直接参与 AI 工作，但没有它们整个系统跑不起来。就像办公室的水电暖，你不直接用它们来工作，但没有它们你什么都干不了。</p><hr><h2 id="五个核心理念-每条都有-血的教训" tabindex="-1">五个核心理念：每条都有&quot;血的教训&quot; <a class="header-anchor" href="#五个核心理念-每条都有-血的教训" aria-label="Permalink to &quot;五个核心理念：每条都有&quot;血的教训&quot;&quot;">​</a></h2><p>ECC 的设计不是拍脑袋想出来的，是 10 个月高强度实战中总结出来的。每一条理念背后，都有踩过的坑：</p><h3 id="理念一-agent-first-能用专家就用专家" tabindex="-1">理念一：Agent-First（能用专家就用专家） <a class="header-anchor" href="#理念一-agent-first-能用专家就用专家" aria-label="Permalink to &quot;理念一：Agent-First（能用专家就用专家）&quot;">​</a></h3><p><strong>血的教训：</strong> 最早 ECC 没有 Agent 系统，所有事都靠主 Agent（Claude Code）一个人干。结果发现：主 Agent 的上下文窗口有限，塞太多系统提示词后，留给实际任务的空间就不够了。而且&quot;通才&quot;做出来的活儿，质量比不上&quot;专才&quot;。</p><p><strong>为什么这个方案：</strong> 把不同任务分发给专门的 Agent。每个 Agent 的 system prompt 只包含跟自己职责相关的指令，更短更精准。比如 Security-Reviewer 的提示词里全是安全检查规则，不需要知道怎么写测试。这样每个 Agent 在自己的领域内做得更好，而且主 Agent 的上下文也更干净。</p><p><strong>对你的启发：</strong> 如果你在构建自己的 AI 工作流，别试图让一个 prompt 干所有事。拆成多个专门的 Agent，每个 Agent 聚焦一件事，整体效果会好很多。</p><h3 id="理念二-test-driven-先写测试-再写代码" tabindex="-1">理念二：Test-Driven（先写测试，再写代码） <a class="header-anchor" href="#理念二-test-driven-先写测试-再写代码" aria-label="Permalink to &quot;理念二：Test-Driven（先写测试，再写代码）&quot;">​</a></h3><p><strong>血的教训：</strong> AI 写的代码你敢直接用吗？说实话，大部分人不敢。AI 有时候会写出&quot;看着对但有边界 bug&quot;的代码，你肉眼很难看出来。没有测试，你永远不知道代码到底对不对。</p><p><strong>为什么这个方案：</strong> 先写测试（定义&quot;正确&quot;是什么），再写代码（让测试通过）。测试是唯一的自动化验证手段。人可以看走眼，但测试不会骗人。ECC 把 80%+ 测试覆盖率作为硬性要求，不是为了指标好看，是因为只有这样才能放心地让 AI 写代码。</p><p><strong>对你的启发：</strong> 不管你用不用 ECC，在 AI 写代码的工作流里加上&quot;先写测试&quot;这一步，你会省掉很多 debug 的时间。</p><h3 id="理念三-security-first-安全不是事后补救" tabindex="-1">理念三：Security-First（安全不是事后补救） <a class="header-anchor" href="#理念三-security-first-安全不是事后补救" aria-label="Permalink to &quot;理念三：Security-First（安全不是事后补救）&quot;">​</a></h3><p><strong>血的教训：</strong> AI 写代码的时候，有时候会把 API key 硬编码到配置文件里。你可能觉得&quot;我不会犯这种错误&quot;——但 AI 会，而且你不一定会注意到。一旦提交到 GitHub，后果很严重。</p><p><strong>为什么这个方案：</strong> 在 Hooks 里加入安全扫描，在提交前自动检测硬编码密钥、SQL 注入风险、不安全的依赖。安全检查不是&quot;可选的加分项&quot;，是&quot;必须通过的门槛&quot;。</p><p><strong>对你的启发：</strong> AI 是一个&quot;听话但没常识&quot;的员工。TA 会执行你的指令，但不一定理解安全后果。你需要在流程里加上安全检查，而不是依赖 AI 自己&quot;注意安全&quot;。</p><h3 id="理念四-plan-before-execute-先规划再动手" tabindex="-1">理念四：Plan Before Execute（先规划再动手） <a class="header-anchor" href="#理念四-plan-before-execute-先规划再动手" aria-label="Permalink to &quot;理念四：Plan Before Execute（先规划再动手）&quot;">​</a></h3><p><strong>血的教训：</strong> 你跟 AI 说&quot;帮我重构这个模块&quot;，AI 直接开始改代码。改到一半你发现方向错了——TA 理解的需求跟你实际想要的不一样。但代码已经改了一半，回退也不是，继续也不是，非常尴尬。</p><p><strong>为什么这个方案：</strong> 强制要求&quot;先规划再执行&quot;。在 AI 动手改代码之前，先让 Planner 出一个方案，你确认后再执行。就像装修房子，你不会让工人直接开工——你会先出个设计图，你看了满意，再开始施工。</p><p><strong>对你的启发：</strong> 复杂任务一定要先让 AI 列出计划。你可以用 <code>/plan</code> 命令触发，或者直接说&quot;先别动手，先告诉我你打算怎么做&quot;。多花 2 分钟确认方案，能省掉 20 分钟的返工。</p><h3 id="理念五-immutability-不改旧东西-只造新东西" tabindex="-1">理念五：Immutability（不改旧东西，只造新东西） <a class="header-anchor" href="#理念五-immutability-不改旧东西-只造新东西" aria-label="Permalink to &quot;理念五：Immutability（不改旧东西，只造新东西）&quot;">​</a></h3><p><strong>血的教训：</strong> AI 修改一个对象的属性时，直接在原对象上改了。结果其他地方引用这个对象的代码也跟着变了，出了一个很难排查的 bug。你花了一下午 debug，最后发现是 AI &quot;好心&quot;改了一个不该改的值。</p><p><strong>为什么这个方案：</strong> Rules 强制要求：创建新对象返回，绝不修改原有对象。这看起来有点死板，但在 AI 编写代码的场景下，&quot;不可变&quot;比&quot;灵活&quot;更重要。因为你无法预测 AI 会在哪里修改什么，但你可以确定 TA 不会意外改掉你依赖的东西。</p><p><strong>对你的启发：</strong> 如果你让 AI 写处理数据的代码，加上&quot;不可变&quot;这条规则。少一个 bug 排查，多一点确定性。</p><hr><h2 id="完整架构图-六大模块怎么配合" tabindex="-1">完整架构图：六大模块怎么配合 <a class="header-anchor" href="#完整架构图-六大模块怎么配合" aria-label="Permalink to &quot;完整架构图：六大模块怎么配合&quot;">​</a></h2>',38)),(A(),s(n,null,{default:o(()=>[E(a,{id:"mermaid-162",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20USER(%5B%22%F0%9F%91%A4%20%E4%BD%A0%22%5D)%0A%0A%20%20%20%20subgraph%20ECC%5B%22%F0%9F%8F%A2%20Everything%20Claude%20Code%22%5D%0A%20%20%20%20%20%20%20%20direction%20TB%0A%0A%20%20%20%20%20%20%20%20subgraph%20PERCEPTION%5B%22%E6%84%9F%E7%9F%A5%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20HOOKS%5B%22%F0%9F%AA%9D%20Hooks%5Cn%E8%A7%A6%E5%8F%91%E5%99%A8%E7%B3%BB%E7%BB%9F%22%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20INTERFACE%5B%22%E6%8E%A5%E5%8F%A3%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20CMDS%5B%22%E2%9A%A1%20Commands%5Cn%E5%BF%AB%E6%8D%B7%E5%91%BD%E4%BB%A4%22%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20KNOWLEDGE%5B%22%E7%9F%A5%E8%AF%86%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20SKLS%5B%22%F0%9F%93%9A%20Skills%5Cn%E6%8A%80%E8%83%BD%E5%8C%85%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20RLS%5B%22%F0%9F%93%8B%20Rules%5Cn%E8%A7%84%E5%88%99%E4%BD%93%E7%B3%BB%22%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20EXEC%5B%22%E6%89%A7%E8%A1%8C%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20AGENTS%5B%22%F0%9F%91%A5%20Agents%5Cn%E4%B8%93%E5%AE%B6%E5%9B%A2%E9%98%9F%22%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20subgraph%20INFRA%5B%22%E5%9F%BA%E5%BB%BA%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20SCR%5B%22%F0%9F%94%A7%20Scripts%5Cn%E5%B7%A5%E5%85%B7%E8%84%9A%E6%9C%AC%22%5D%0A%20%20%20%20%20%20%20%20end%0A%0A%20%20%20%20%20%20%20%20HOOKS%20--%3E%7C%22%E8%A7%A6%E5%8F%91%E6%97%B6%E6%9C%BA%22%7C%20AGENTS%0A%20%20%20%20%20%20%20%20CMDS%20--%3E%7C%22%E7%94%A8%E6%88%B7%E6%8C%87%E4%BB%A4%22%7C%20AGENTS%0A%20%20%20%20%20%20%20%20SKLS%20--%3E%7C%22%E9%A2%86%E5%9F%9F%E7%9F%A5%E8%AF%86%22%7C%20AGENTS%0A%20%20%20%20%20%20%20%20RLS%20--%3E%7C%22%E8%A1%8C%E4%B8%BA%E7%BA%A6%E6%9D%9F%22%7C%20AGENTS%0A%20%20%20%20%20%20%20%20SCR%20-.-%3E%7C%22%E7%8E%AF%E5%A2%83%E6%94%AF%E6%92%91%22%7C%20HOOKS%0A%20%20%20%20end%0A%0A%20%20%20%20USER%20--%3E%7C%22%E8%87%AA%E7%84%B6%E8%AF%AD%E8%A8%80%E6%88%96%E6%96%9C%E6%9D%A0%E5%91%BD%E4%BB%A4%22%7C%20CMDS%0A%20%20%20%20USER%20--%3E%7C%22%E7%9B%B4%E6%8E%A5%E5%AF%B9%E8%AF%9D%22%7C%20AGENTS%0A%20%20%20%20AGENTS%20--%3E%7C%22%E5%86%99%E4%BB%A3%E7%A0%81%E3%80%81%E8%B7%91%E6%B5%8B%E8%AF%95%E3%80%81%E5%AE%A1%E6%9F%A5%22%7C%20OUT(%5B%22%F0%9F%93%81%20%E4%BD%A0%E7%9A%84%E9%A1%B9%E7%9B%AE%22%5D)%0A%0A%20%20%20%20style%20USER%20fill%3A%2342a5f5%2Ccolor%3A%23fff%0A%20%20%20%20style%20HOOKS%20fill%3A%23e91e63%2Ccolor%3A%23fff%0A%20%20%20%20style%20CMDS%20fill%3A%2300bcd4%2Ccolor%3A%23fff%0A%20%20%20%20style%20SKLS%20fill%3A%234caf50%2Ccolor%3A%23fff%0A%20%20%20%20style%20RLS%20fill%3A%23673ab7%2Ccolor%3A%23fff%0A%20%20%20%20style%20AGENTS%20fill%3A%239c27b0%2Ccolor%3A%23fff%0A%20%20%20%20style%20SCR%20fill%3A%233f51b5%2Ccolor%3A%23fff%0A%20%20%20%20style%20OUT%20fill%3A%23ff9800%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[r(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=e(`<p>用户通过自然语言或斜杠命令跟 ECC 交互。Commands 把你的意图翻译成系统能理解的操作，Hooks 在正确时机触发对应的 Agent，Agent 在 Rules 的约束下，参考 Skills 的知识，执行具体任务。Scripts 在底层确保一切环境就绪。</p><hr><h2 id="与其他工具的对比-设计哲学的差异" tabindex="-1">与其他工具的对比：设计哲学的差异 <a class="header-anchor" href="#与其他工具的对比-设计哲学的差异" aria-label="Permalink to &quot;与其他工具的对比：设计哲学的差异&quot;">​</a></h2><p>你可能在想：Cursor 也有 AI 辅助、GitHub Copilot 也能写代码、我自己写 <code>.claude</code> 配置也能用——ECC 有什么不同？</p><p>关键不在于功能列表的差异，而在于<strong>设计哲学的差异</strong>：</p><table tabindex="0"><thead><tr><th>特性</th><th>ECC</th><th>Cursor</th><th>Copilot</th><th>手写配置</th></tr></thead><tbody><tr><td>设计哲学</td><td>完整控制系统</td><td>编辑器增强</td><td>代码补全</td><td>自定义</td></tr><tr><td>会话记忆</td><td>✅ 跨会话持久化</td><td>❌ 每次重新开始</td><td>❌</td><td>手动管理</td></tr><tr><td>自动化 Hooks</td><td>✅ 20+ 预设触发器</td><td>❌</td><td>❌</td><td>自己写</td></tr><tr><td>专家团队</td><td>✅ 28 个专门 Agent</td><td>❌ 单一模型</td><td>❌</td><td>自己配</td></tr><tr><td>安全检查</td><td>✅ 自动扫描</td><td>❌</td><td>基础</td><td>自己写</td></tr><tr><td>跨会话学习</td><td>✅ 持续学习</td><td>❌</td><td>❌</td><td>无</td></tr><tr><td>多 Harness 支持</td><td>✅ Claude/Codex/Cursor</td><td>仅 Cursor</td><td>仅 Copilot</td><td>看情况</td></tr></tbody></table><p><strong>核心差异是什么？</strong></p><ul><li><strong>Cursor</strong> 的思路是&quot;给编辑器加 AI&quot;——AI 是辅助功能，你在编辑器里写代码，AI 帮你补全、解释、重构。重点是编辑体验。</li><li><strong>Copilot</strong> 的思路是&quot;给 IDE 加自动补全&quot;——AI 是一个更聪明的 IntelliSense，你写代码时 TA 在旁边提供建议。重点是代码生成。</li><li><strong>ECC</strong> 的思路是&quot;给 AI Agent 装操作系统&quot;——AI 是主角，你是导演。你告诉 AI 要做什么，ECC 确保 AI 做得对、做得好、做得安全。重点是控制和自动化。</li></ul><p><strong>简单来说：</strong> 别人在造锤子，ECC 在建工坊。锤子解决&quot;钉钉子&quot;的问题，工坊解决&quot;做一个产品&quot;的问题。你需要的不只是一个工具，而是一套工作系统。</p><hr><h2 id="安装-一行命令的事" tabindex="-1">安装：一行命令的事 <a class="header-anchor" href="#安装-一行命令的事" aria-label="Permalink to &quot;安装：一行命令的事&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 安装 ECC</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/affaan-m/everything-claude-code/main/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>就这么简单。安装完成后，ECC 会自动：</p><ol><li>把 Hooks 配置写入你的 Claude Code 配置</li><li>安装 28 个 Agents 到正确位置</li><li>部署 125 个 Skills</li><li>配置 Rules 和 Commands</li><li>检测你的项目语言和框架，适配相应的规则</li></ol><p><strong>你不需要理解每个模块的细节</strong> —— 默认配置就已经很好用了。后面几篇会帮你深入理解每个部分为什么要这么设计。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>现在你知道 ECC 长什么样了。接下来读 <a href="./02-Hooks系统.html">02-Hooks系统</a>，了解&quot;智能门禁系统&quot;是怎么工作的——这是整个 ECC 自动化的核心。理解了 Hooks，你就理解了 ECC 一半的魔力。</p>`,18))])}const S=l(u,[["render",C]]);export{f as __pageData,S as default};
